import React from 'react';
import { Menu, Lightbulb, Bell } from 'lucide-react';

const Header = ({ onToggleInsights, showInsights }) => {
  return (
    <header className="bg-white border-b border-slate-200 h-16 flex items-center justify-between px-6 lg:px-10 shrink-0 z-10">
      <div className="flex items-center gap-4">
        <button className="md:hidden text-slate-500 hover:text-slate-800">
          <Menu size={24} />
        </button>
        <h1 className="text-xl font-bold text-slate-800 hidden sm:block">FinTech Mobile App v2.4.0 (RC1)</h1>
      </div>

      <div className="flex items-center gap-4">
        {/* 코멘트 토글 버튼 */}
        <button 
          onClick={onToggleInsights}
          className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium border transition-colors shadow-sm ${
            showInsights 
              ? 'bg-indigo-600 text-white border-indigo-600' 
              : 'bg-indigo-50 text-indigo-700 border-indigo-100 hover:bg-indigo-100'
          }`}
        >
          <Lightbulb size={16} />
          <span>Kyle의 코멘트 ({showInsights ? 'On' : 'Off'})</span>
        </button>

        <button className="w-8 h-8 flex items-center justify-center text-slate-400 hover:text-slate-600 relative">
          <Bell size={20} />
          <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full"></span>
        </button>
      </div>
    </header>
  );
};

export default Header;
